/// <summary>
///    The <c>ETGPurchRegisterReportUIBuilder</c> class is the user interface builder class for the associated SQL
///    Server Reporting Services (SSRS) report.
/// </summary>
class Etg_RegisterSalesReportUIBuilder extends SrsReportDataContractUIBuilder
{

        Etg_RegisterSalesReportContract     contract;
        DialogField                         invoiceId;
        DialogField                         custAccount;
        DialogField         finDimSet;




}

Method.Source:
/// <summary>
///    building all parameters
/// </summary>
public void build()
{
    contract = this.dataContractObject();

this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmFromDate), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmToDate), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmFinancialDimSet), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmIsDetailReport), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewConfigId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventSizeId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventColorId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventStyleId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventSiteId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventLocationId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewWMSLocationId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewLicensePlateId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventStatus), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventBatchId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventSerialId), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmViewInventOwnerId_RU), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmBusinessSegment), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmConnectionType), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmCustAccount), contract);
this.addDialogField(methodStr(Etg_RegisterSalesReportContract, parmInvoiceId), contract);
}

    /// <summary>
    ///    creating dialog fields
    /// </summary>
    public void postBuild()
    {
        Dialog dialogobj    = this.dialog();

    finDimSet = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(Etg_RegisterSalesReportContract, parmFinancialDimSet));
    finDimSet.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(Etg_RegisterSalesReportUIBuilder, finDimSetLookup), this);
    custAccount = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(Etg_RegisterSalesReportContract, parmCustAccount));
    custAccount.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(Etg_RegisterSalesReportUIBuilder,custAccountMultiSelectLookup),this);
    invoiceId = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(Etg_RegisterSalesReportContract, parmInvoiceId));
    invoiceId.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(Etg_RegisterSalesReportUIBuilder,InvoiceIdMultiSelectLookup ),this);

}

public void postRun()
{
    Etg_RegisterSalesReportContract etgRegisterSalesReportContract = this.dataContractObject();
}

/// <summary>
///    creating dimension sets lookup
/// </summary>
/// <param name = "_formStringControl">form string control</param>
public void finDimSetLookup(FormStringControl   _formStringControl)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tablenum(DimensionHierarchy), _formStringControl);

    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Name));
    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Description));

    qbds = query.addDataSource(tableNum(DimensionHierarchy));
    qbds.addRange(fieldNum(DimensionHierarchy, StructureType)).value(queryValue(DimensionHierarchyType::Focus));
    qbds.addRange(fieldNum(DimensionHierarchy, IsSystemGenerated)).value(queryValue(NoYes::No));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
/// Multiselect lookup for cust account parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void custAccountMultiSelectLookup(FormStringControl _control)
{
    Query                 query = new Query();
    QueryBuildDataSource  qbds;
    container             conCustTable;

    qbds = query.addDataSource(tableNum(CustTable));

    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(CustTable,AccountNum));

    qbds = qbds.addDataSource(tableNum(DirPartyTable));
    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(DirPartyTable,Name));
    qbds.relations(true);
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conCustTable);
}

/// <summary>
/// Multi select lookup for InvoiceId parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void InvoiceIdMultiSelectLookup(FormStringControl _control)
{
    Query  query = new Query();
    QueryBuildDataSource qbds;
    container conInvoiceId;
    qbds = query.addDataSource(tableNum(CustInvoiceJour));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceId));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, SalesId));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceAccount));
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conInvoiceId);
}
